#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    getchar(); // consume newline after T
    char s1[105];
    char s2[105];
    for(int i=0;i<T;++i){
        if(!fgets(s1,sizeof(s1),stdin)) s1[0]='\0';
        if(!fgets(s2,sizeof(s2),stdin)) s2[0]='\0';
        s1[strcspn(s1,"\n")]='\0';
        s2[strcspn(s2,"\n")]='\0';
        printf("%s %s",s1,s2);
        if(i!=T-1) printf("\n");
    }
    return 0;
}

